# Extract scores and basic info
scores = []
for i, trace in enumerate(traces):
    feedback = trace['Feedback']
    inputs = trace['Inputs']

    # Find score
    score = None
    if isinstance(feedback, dict):
        score = feedback.get('score', feedback.get('Score', None))
        if score is None:
            # Try to find score in nested structure
            for k, v in feedback.items():
                if 'score' in str(k).lower():
                    score = v
                    break

    task_instruction = inputs.get('instruction', inputs.get('task', 'N/A'))
    if isinstance(task_instruction, str) and len(task_instruction) > 100:
        task_instruction = task_instruction[:100] + "..."

    scores.append({
        'index': i,
        'score': score,
        'instruction': task_instruction
    })

print("Score distribution:")
for s in sorted(scores, key=lambda x: x['score'] if x['score'] is not None else -1):
    print(f"  Trace {s['index']}: score={s['score']:.4f} | {s['instruction'][:80]}")
